/**
 * Page JSON Editor - Full Page JSON View & Edit
 * Purpose: View and edit complete page JSON with validation
 * Author: generated by Amazon Q
 * Created: 2024-01-15
 */

'use client';

import React, { useState, useEffect } from 'react';
import { SectionConfig } from '@/lib/page-builder/section-schemas';

interface PageJSONEditorProps {
  sections: SectionConfig[];
  onSave: (sections: SectionConfig[]) => void;
  onClose: () => void;
}

interface ValidationError {
  line?: number;
  message: string;
  path?: string;
}

export function PageJSONEditor({ sections, onSave, onClose }: PageJSONEditorProps) {
  const [jsonText, setJsonText] = useState('');
  const [errors, setErrors] = useState<ValidationError[]>([]);
  const [isValid, setIsValid] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [highlightedLine, setHighlightedLine] = useState<number | null>(null);
  const [copied, setCopied] = useState(false);
  const textareaRef = React.useRef<HTMLTextAreaElement>(null);

  // Initialize JSON text from sections
  useEffect(() => {
    try {
      const formatted = JSON.stringify(sections, null, 2);
      setJsonText(formatted);
      setErrors([]);
      setIsValid(true);
    } catch (error) {
      console.error('Failed to serialize sections:', error);
      setErrors([{ message: 'Failed to load page data' }]);
      setIsValid(false);
    }
  }, [sections]);

  // Validate JSON on change
  const handleJsonChange = (value: string) => {
    setJsonText(value);
    
    const validationErrors: ValidationError[] = [];
    
    try {
      // Try to parse JSON
      const parsed = JSON.parse(value);
      
      // Validate structure
      if (!Array.isArray(parsed)) {
        validationErrors.push({
          message: 'Root element must be an array of sections',
          path: 'root'
        });
      } else {
        // Validate each section
        parsed.forEach((section: any, index: number) => {
          // Check required fields
          if (!section.id) {
            validationErrors.push({
              message: `Section ${index}: Missing required field "id"`,
              path: `[${index}].id`
            });
          }
          
          if (!section.type) {
            validationErrors.push({
              message: `Section ${index}: Missing required field "type"`,
              path: `[${index}].type`
            });
          }
          
          if (section.order === undefined) {
            validationErrors.push({
              message: `Section ${index}: Missing required field "order"`,
              path: `[${index}].order`
            });
          }
          
          if (!section.data) {
            validationErrors.push({
              message: `Section ${index}: Missing required field "data"`,
              path: `[${index}].data`
            });
          }
          
          // Check for duplicate IDs
          const duplicates = parsed.filter((s: any) => s.id === section.id);
          if (duplicates.length > 1) {
            validationErrors.push({
              message: `Section ${index}: Duplicate ID "${section.id}"`,
              path: `[${index}].id`
            });
          }
        });
      }
      
      setErrors(validationErrors);
      setIsValid(validationErrors.length === 0);
      
    } catch (error) {
      // JSON parse error
      const parseError = error as SyntaxError;
      const match = parseError.message.match(/position (\d+)/);
      
      let lineNumber: number | undefined;
      if (match) {
        const position = parseInt(match[1]);
        lineNumber = value.substring(0, position).split('\n').length;
      }
      
      validationErrors.push({
        line: lineNumber,
        message: `JSON Syntax Error: ${parseError.message}`,
        path: 'syntax'
      });
      
      setErrors(validationErrors);
      setIsValid(false);
    }
  };

  // Handle save
  const handleSave = () => {
    if (!isValid) {
      alert('Cannot save: Please fix validation errors first');
      return;
    }
    
    try {
      setIsSaving(true);
      const parsed = JSON.parse(jsonText) as SectionConfig[];
      onSave(parsed);
      onClose();
    } catch (error) {
      console.error('Failed to save:', error);
      alert('Failed to save changes');
    } finally {
      setIsSaving(false);
    }
  };

  // Format JSON
  const handleFormat = () => {
    try {
      const parsed = JSON.parse(jsonText);
      const formatted = JSON.stringify(parsed, null, 2);
      setJsonText(formatted);
    } catch (error) {
      // Keep current text if parsing fails
      alert('Cannot format: Invalid JSON syntax');
    }
  };

  // Minify JSON
  const handleMinify = () => {
    try {
      const parsed = JSON.parse(jsonText);
      const minified = JSON.stringify(parsed);
      setJsonText(minified);
    } catch (error) {
      alert('Cannot minify: Invalid JSON syntax');
    }
  };

  // Copy JSON to clipboard
  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(jsonText);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (error) {
      alert('Failed to copy to clipboard');
    }
  };

  // Jump to specific line
  const jumpToLine = (lineNumber: number) => {
    if (!textareaRef.current) return;
    
    const lines = jsonText.split('\n');
    let charCount = 0;
    
    for (let i = 0; i < lineNumber - 1 && i < lines.length; i++) {
      charCount += lines[i].length + 1; // +1 for newline
    }
    
    textareaRef.current.focus();
    textareaRef.current.setSelectionRange(charCount, charCount + (lines[lineNumber - 1]?.length || 0));
    textareaRef.current.scrollTop = (lineNumber - 1) * 21; // approximate line height
    
    setHighlightedLine(lineNumber);
    setTimeout(() => setHighlightedLine(null), 2000);
  };

  // Keyboard shortcuts
  React.useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Ctrl+S or Cmd+S: Save
      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
        e.preventDefault();
        if (isValid) handleSave();
      }
      
      // Escape: Close
      if (e.key === 'Escape') {
        e.preventDefault();
        onClose();
      }
      
      // Ctrl+Shift+F or Cmd+Shift+F: Format
      if ((e.ctrlKey || e.metaKey) && e.shiftKey && e.key === 'F') {
        e.preventDefault();
        handleFormat();
      }
    };
    
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [isValid, jsonText, onClose]);

  // Calculate line numbers
  const lineCount = jsonText.split('\n').length;

  return (
    <div className="fixed inset-0 z-50 bg-black/50 flex items-center justify-center p-4">
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow-2xl w-full max-w-7xl h-[90vh] flex flex-col">
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-gray-200 dark:border-gray-700">
          <div className="flex items-center gap-4">
            <h2 className="text-xl font-semibold text-gray-900 dark:text-white">
              Page JSON Editor
            </h2>
            <div className={`px-3 py-1 rounded-full text-sm font-medium ${
              isValid 
                ? 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400'
                : 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400'
            }`}>
              {isValid ? '✓ Valid JSON' : `✗ ${errors.length} Error${errors.length > 1 ? 's' : ''}`}
            </div>
          </div>
          
          <button
            onClick={onClose}
            className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg transition-colors"
          >
            <svg className="w-6 h-6 text-gray-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        {/* Toolbar */}
        <div className="flex items-center gap-2 px-6 py-3 border-b border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-900">
          <button
            onClick={handleFormat}
            className="px-3 py-1.5 text-sm bg-blue-600 hover:bg-blue-700 text-white rounded-lg transition-colors"
            title="Format JSON (Ctrl+Shift+F)"
          >
            Format
          </button>
          <button
            onClick={handleMinify}
            className="px-3 py-1.5 text-sm bg-gray-600 hover:bg-gray-700 text-white rounded-lg transition-colors"
          >
            Minify
          </button>
          <button
            onClick={handleCopy}
            className={`px-3 py-1.5 text-sm rounded-lg transition-colors ${
              copied 
                ? 'bg-green-600 text-white' 
                : 'bg-indigo-600 hover:bg-indigo-700 text-white'
            }`}
          >
            {copied ? '✓ Copied!' : 'Copy JSON'}
          </button>
          <div className="flex-1" />
          <div className="text-sm text-gray-600 dark:text-gray-400">
            {lineCount} lines • {jsonText.length} characters
          </div>
        </div>

        {/* Main Content */}
        <div className="flex-1 flex overflow-hidden">
          {/* Editor with Line Numbers */}
          <div className="flex-1 flex flex-col">
            <div className="flex-1 flex overflow-hidden">
              {/* Line Numbers */}
              <div className="flex-shrink-0 bg-gray-100 dark:bg-gray-800 border-r border-gray-300 dark:border-gray-600 overflow-hidden">
                <div className="py-4 px-3 font-mono text-sm text-gray-500 dark:text-gray-400 text-right select-none" style={{ lineHeight: '1.5' }}>
                  {Array.from({ length: lineCount }, (_, i) => (
                    <div
                      key={i + 1}
                      className={`${
                        highlightedLine === i + 1 
                          ? 'bg-yellow-200 dark:bg-yellow-900/50 text-gray-900 dark:text-yellow-400 font-bold' 
                          : ''
                      }`}
                    >
                      {i + 1}
                    </div>
                  ))}
                </div>
              </div>
              
              {/* Text Editor */}
              <textarea
                ref={textareaRef}
                value={jsonText}
                onChange={(e) => handleJsonChange(e.target.value)}
                className="flex-1 w-full p-4 font-mono text-sm bg-gray-50 dark:bg-gray-900 text-gray-900 dark:text-gray-100 border-0 focus:outline-none resize-none"
                style={{
                  tabSize: 2,
                  lineHeight: '1.5'
                }}
                spellCheck={false}
              />
            </div>
          </div>

          {/* Error Panel */}
          {errors.length > 0 && (
            <div className="w-96 border-l border-gray-200 dark:border-gray-700 bg-red-50 dark:bg-red-900/10 overflow-y-auto">
              <div className="p-4">
                <h3 className="text-sm font-semibold text-red-900 dark:text-red-400 mb-3">
                  Validation Errors ({errors.length})
                </h3>
                <div className="space-y-2">
                  {errors.map((error, index) => (
                    <div
                      key={index}
                      className="p-3 bg-white dark:bg-gray-800 rounded-lg border border-red-200 dark:border-red-800 cursor-pointer hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors"
                      onClick={() => error.line && jumpToLine(error.line)}
                    >
                      {error.line && (
                        <div className="text-xs font-mono text-red-600 dark:text-red-400 mb-1 flex items-center gap-1">
                          <span>Line {error.line}</span>
                          <span className="text-gray-400">→ Click to jump</span>
                        </div>
                      )}
                      {error.path && (
                        <div className="text-xs font-mono text-gray-600 dark:text-gray-400 mb-1">
                          {error.path}
                        </div>
                      )}
                      <div className="text-sm text-gray-900 dark:text-gray-100">
                        {error.message}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="flex items-center justify-between px-6 py-4 border-t border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-900">
          <div className="flex items-center gap-4">
            <div className="text-sm text-gray-600 dark:text-gray-400">
              {isValid ? (
                <span className="text-green-600 dark:text-green-400">
                  ✓ Ready to save
                </span>
              ) : (
                <span className="text-red-600 dark:text-red-400">
                  ✗ Fix errors before saving
                </span>
              )}
            </div>
            <div className="text-xs text-gray-500 dark:text-gray-500">
              Shortcuts: Ctrl+S (Save) • Ctrl+Shift+F (Format) • Esc (Close)
            </div>
          </div>
          
          <div className="flex items-center gap-3">
            <button
              onClick={onClose}
              className="px-4 py-2 text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700 rounded-lg transition-colors"
            >
              Cancel
            </button>
            <button
              onClick={handleSave}
              disabled={!isValid || isSaving}
              className="px-4 py-2 text-sm bg-green-600 hover:bg-green-700 disabled:bg-gray-400 disabled:cursor-not-allowed text-white rounded-lg transition-colors flex items-center gap-2"
            >
              {isSaving ? (
                <>
                  <div className="animate-spin rounded-full h-4 w-4 border-2 border-white border-t-transparent" />
                  Saving...
                </>
              ) : (
                <>
                  <span>💾</span>
                  Save Changes
                </>
              )}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
